import { useEffect, useRef } from 'react';
import * as THREE from 'three';

export default function ThreeBackground({ variant = 'cinema' }) {
  const mountRef = useRef(null);

  useEffect(() => {
    const mount = mountRef.current;
    if (!mount) return;

    const scene = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera(75, mount.clientWidth / mount.clientHeight, 0.1, 1000);
    camera.position.z = 5;

    const renderer = new THREE.WebGLRenderer({ alpha: true, antialias: true });
    renderer.setSize(mount.clientWidth, mount.clientHeight);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    renderer.setClearColor(0x000000, 0);
    mount.appendChild(renderer.domElement);

    let particles, lines, animId;

    if (variant === 'cinema') {
      // Cinema scene: projector beam, film reels, and floating dust.
      camera.position.z = 9;
      scene.fog = new THREE.Fog(0x050505, 8, 24);

      const reelGroup = new THREE.Group();
      scene.add(reelGroup);

      const reelMat = new THREE.MeshStandardMaterial({
        color: 0x181818,
        metalness: 0.9,
        roughness: 0.35
      });

      const holeMat = new THREE.MeshStandardMaterial({
        color: 0x050505,
        metalness: 0.95,
        roughness: 0.2
      });

      const reelA = new THREE.Mesh(new THREE.CylinderGeometry(1.4, 1.4, 0.22, 40), reelMat);
      reelA.position.set(-2.4, 1.4, -0.4);
      reelA.rotation.x = Math.PI / 2;
      reelGroup.add(reelA);

      const reelB = new THREE.Mesh(new THREE.CylinderGeometry(1.15, 1.15, 0.2, 40), reelMat);
      reelB.position.set(2.5, -1.1, 0.6);
      reelB.rotation.x = Math.PI / 2;
      reelGroup.add(reelB);

      const addHoles = (target, radius) => {
        for (let i = 0; i < 6; i++) {
          const angle = (i / 6) * Math.PI * 2;
          const hole = new THREE.Mesh(new THREE.CylinderGeometry(0.15, 0.15, 0.3, 18), holeMat);
          hole.position.set(Math.cos(angle) * radius, Math.sin(angle) * radius, 0);
          hole.rotation.x = Math.PI / 2;
          target.add(hole);
        }
      };

      addHoles(reelA, 0.72);
      addHoles(reelB, 0.62);

      const beam = new THREE.Mesh(
        new THREE.ConeGeometry(2.4, 11, 40, 1, true),
        new THREE.MeshBasicMaterial({
          color: 0xffd9a3,
          transparent: true,
          opacity: 0.15,
          side: THREE.DoubleSide,
          depthWrite: false,
          blending: THREE.AdditiveBlending
        })
      );
      beam.position.set(-4.6, 0.5, -4.8);
      beam.rotation.z = -Math.PI / 2.8;
      beam.rotation.y = -0.25;
      scene.add(beam);

      const dustGeo = new THREE.BufferGeometry();
      const count = 2200;
      const positions = new Float32Array(count * 3);
      for (let i = 0; i < count; i++) {
        positions[i * 3] = (Math.random() - 0.5) * 18;
        positions[i * 3 + 1] = (Math.random() - 0.5) * 10;
        positions[i * 3 + 2] = (Math.random() - 0.5) * 16;
      }
      dustGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
      particles = new THREE.Points(
        dustGeo,
        new THREE.PointsMaterial({
          size: 0.03,
          color: 0xfff1cf,
          transparent: true,
          opacity: 0.4,
          depthWrite: false
        })
      );
      scene.add(particles);

      const keyLight = new THREE.PointLight(0xffd6a0, 3.1, 30, 2);
      keyLight.position.set(-4.8, 1.2, 1.5);
      scene.add(keyLight);

      const fillLight = new THREE.PointLight(0xe50914, 1.1, 24, 2);
      fillLight.position.set(4, -2.5, 3);
      scene.add(fillLight);

      const ambient = new THREE.AmbientLight(0x331a16, 0.6);
      scene.add(ambient);

      let t = 0;
      const animate = () => {
        animId = requestAnimationFrame(animate);
        t += 0.008;

        reelA.rotation.z += 0.01;
        reelB.rotation.z -= 0.012;
        reelGroup.rotation.y = Math.sin(t * 0.4) * 0.08;

        beam.material.opacity = 0.12 + Math.sin(t * 2.8) * 0.03;

        const pos = dustGeo.attributes.position.array;
        for (let i = 0; i < count; i++) {
          pos[i * 3 + 1] += 0.002 + Math.sin(t + i * 0.03) * 0.0007;
          if (pos[i * 3 + 1] > 5.2) pos[i * 3 + 1] = -5.2;
        }
        dustGeo.attributes.position.needsUpdate = true;

        renderer.render(scene, camera);
      };
      animate();
    }

    if (variant === 'stars') {
      // Starfield
      const geo = new THREE.BufferGeometry();
      const count = 3000;
      const positions = new Float32Array(count * 3);
      const colors = new Float32Array(count * 3);

      for (let i = 0; i < count; i++) {
        positions[i * 3] = (Math.random() - 0.5) * 30;
        positions[i * 3 + 1] = (Math.random() - 0.5) * 30;
        positions[i * 3 + 2] = (Math.random() - 0.5) * 30;

        const color = Math.random();
        if (color < 0.33) { colors[i*3]=1; colors[i*3+1]=0.3; colors[i*3+2]=0.3; } // red
        else if (color < 0.66) { colors[i*3]=0.3; colors[i*3+1]=0.6; colors[i*3+2]=1; } // blue
        else { colors[i*3]=1; colors[i*3+1]=1; colors[i*3+2]=1; } // white
      }

      geo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
      geo.setAttribute('color', new THREE.BufferAttribute(colors, 3));

      const mat = new THREE.PointsMaterial({
        size: 0.05, vertexColors: true, transparent: true, opacity: 0.8
      });
      particles = new THREE.Points(geo, mat);
      scene.add(particles);

      let t = 0;
      const animate = () => {
        animId = requestAnimationFrame(animate);
        t += 0.0003;
        particles.rotation.x = t * 0.2;
        particles.rotation.y = t * 0.3;
        const pos = geo.attributes.position.array;
        for (let i = 0; i < count; i++) {
          pos[i * 3 + 2] += 0.005;
          if (pos[i * 3 + 2] > 15) pos[i * 3 + 2] = -15;
        }
        geo.attributes.position.needsUpdate = true;
        renderer.render(scene, camera);
      };
      animate();
    }

    if (variant === 'network') {
      // Neural network / DNA-like particles
      const geo = new THREE.BufferGeometry();
      const count = 200;
      const positions = new Float32Array(count * 3);
      const nodePositions = [];

      for (let i = 0; i < count; i++) {
        const angle = (i / count) * Math.PI * 2 * 5;
        const radius = 2 + Math.sin(i * 0.3) * 1;
        const x = Math.cos(angle) * radius + (Math.random() - 0.5) * 2;
        const y = (i / count) * 10 - 5 + (Math.random() - 0.5);
        const z = Math.sin(angle) * radius + (Math.random() - 0.5) * 2;
        positions[i * 3] = x;
        positions[i * 3 + 1] = y;
        positions[i * 3 + 2] = z;
        nodePositions.push(new THREE.Vector3(x, y, z));
      }

      geo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
      const mat = new THREE.PointsMaterial({ size: 0.06, color: 0xe50914, transparent: true, opacity: 0.7 });
      particles = new THREE.Points(geo, mat);
      scene.add(particles);

      // Lines between nearby points
      const lineGeo = new THREE.BufferGeometry();
      const linePositions = [];
      for (let i = 0; i < nodePositions.length; i++) {
        for (let j = i + 1; j < nodePositions.length; j++) {
          if (nodePositions[i].distanceTo(nodePositions[j]) < 1.5) {
            linePositions.push(nodePositions[i].x, nodePositions[i].y, nodePositions[i].z);
            linePositions.push(nodePositions[j].x, nodePositions[j].y, nodePositions[j].z);
          }
        }
      }
      lineGeo.setAttribute('position', new THREE.BufferAttribute(new Float32Array(linePositions), 3));
      lines = new THREE.LineSegments(lineGeo, new THREE.LineBasicMaterial({ color: 0xe50914, transparent: true, opacity: 0.15 }));
      scene.add(lines);

      camera.position.z = 8;
      let t = 0;
      const animate = () => {
        animId = requestAnimationFrame(animate);
        t += 0.004;
        particles.rotation.y = t * 0.1;
        if (lines) lines.rotation.y = t * 0.1;
        renderer.render(scene, camera);
      };
      animate();
    }

    if (variant === 'nebula') {
      // Nebula-like particle cloud
      const geo = new THREE.BufferGeometry();
      const count = 5000;
      const positions = new Float32Array(count * 3);
      const colors = new Float32Array(count * 3);

      for (let i = 0; i < count; i++) {
        const theta = Math.random() * Math.PI * 2;
        const phi = Math.random() * Math.PI;
        const r = 3 + Math.random() * 4;
        positions[i * 3] = r * Math.sin(phi) * Math.cos(theta);
        positions[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
        positions[i * 3 + 2] = r * Math.cos(phi);

        const h = Math.random();
        colors[i * 3] = h < 0.5 ? 0.9 : 0.4;
        colors[i * 3 + 1] = h < 0.5 ? 0.1 : 0.1;
        colors[i * 3 + 2] = h < 0.5 ? 0.1 : 0.8;
      }

      geo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
      geo.setAttribute('color', new THREE.BufferAttribute(colors, 3));
      particles = new THREE.Points(geo, new THREE.PointsMaterial({ size: 0.04, vertexColors: true, transparent: true, opacity: 0.6 }));
      scene.add(particles);

      let t = 0;
      const animate = () => {
        animId = requestAnimationFrame(animate);
        t += 0.001;
        particles.rotation.x = Math.sin(t) * 0.3;
        particles.rotation.y = t * 0.15;
        renderer.render(scene, camera);
      };
      animate();
    }

    const handleResize = () => {
      if (!mount) return;
      camera.aspect = mount.clientWidth / mount.clientHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(mount.clientWidth, mount.clientHeight);
    };
    window.addEventListener('resize', handleResize);

    return () => {
      cancelAnimationFrame(animId);
      window.removeEventListener('resize', handleResize);
      renderer.dispose();
      if (mount.contains(renderer.domElement)) mount.removeChild(renderer.domElement);
    };
  }, [variant]);

  return (
    <div ref={mountRef} style={{
      position: 'fixed', top: 0, left: 0, width: '100%', height: '100%',
      zIndex: 0, pointerEvents: 'none'
    }} />
  );
}
